// CUDA Kernels translated from OpenCL
__global__ void Fan1_kernel(float *m_dev, float *a_dev, float *b_dev, const int size, const int t) {
    int globalId = blockIdx.x * blockDim.x + threadIdx.x;

    if (globalId < size-1-t) {
        // *(m_dev + size * (globalId + t + 1)+t) = *(a_dev + size * (globalId + t + 1) + t) / *(a_dev + size * t + t);
        m_dev[size * (globalId + t + 1) + t] = a_dev[size * (globalId + t + 1) + t] / a_dev[size * t + t];
    }
}

__global__ void Fan2_kernel(float *m_dev, float *a_dev, float *b_dev, const int size, const int t) {
    int globalIdx = blockIdx.x * blockDim.x + threadIdx.x;
    int globalIdy = blockIdx.y * blockDim.y + threadIdx.y;

    if (globalIdx < size-1-t && globalIdy < size-t) {
        // a_dev[size*(globalIdx+1+t)+(globalIdy+t)] -= m_dev[size*(globalIdx+1+t)+t] * a_dev[size*t+(globalIdy+t)];
        float m_val = m_dev[size * (globalIdx + 1 + t) + t];
        float a_diag = a_dev[size * t + (globalIdy + t)];
        a_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] -= m_val * a_diag;

        if(globalIdy == 0){
            // b_dev[globalIdx+1+t] -= m_dev[size*(globalIdx+1+t)+(globalIdy+t)] * b_dev[t];
            // Note: In the source, globalIdy is 0 here, so index is size*(globalIdx+1+t)+0
            b_dev[globalIdx + 1 + t] -= m_dev[size * (globalIdx + 1 + t) + t] * b_dev[t];
        }
    }
}

// Helper functions for CUDA launchers
void cuda_fan1_launcher(void (*func)(int, int), int count, int t_val, int size_val, float *m_dev, float *a_dev, float *b_dev) {
    // This function mimics the GenOnI behavior by launching the kernel
    // The 'func' argument is ignored in the CUDA path as we launch directly
    int block_size = 256;
    int num_blocks = (count + block_size - 1) / block_size;

    dim3 dimBlock(block_size);
    dim3 dimGrid(num_blocks);

    Fan1_kernel<<<dimGrid, dimBlock>>>(m_dev, a_dev, b_dev, size_val, t_val);
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA Error launching Fan1: %s\n", cudaGetErrorString(err));
        exit(1);
    }
    cudaDeviceSynchronize();
}

void cuda_fan2_launcher(void (*func)(int, int, int), int count_x, int count_y, int t_val, int size_val, float *m_dev, float *a_dev, float *b_dev) {
    int block_size_x = 16;
    int block_size_y = 16;
    int num_blocks_x = (count_x + block_size_x - 1) / block_size_x;
    int num_blocks_y = (count_y + block_size_y - 1) / block_size_y;

    dim3 dimBlock(block_size_x, block_size_y);
    dim3 dimGrid(num_blocks_x, num_blocks_y);

    Fan2_kernel<<<dimGrid, dimBlock>>>(m_dev, a_dev, b_dev, size_val, t_val);
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA Error launching Fan2: %s\n", cudaGetErrorString(err));
        exit(1);
    }
    cudaDeviceSynchronize();
}

