// CUDA specific Forward Substitution using kernels
void ForwardSub_CUDA(float *m_dev, float *a_dev, float *b_dev, int size) {
    for (t = 0; t < (size - 1); t++) {
        // Launch Fan1
        cuda_fan1_launcher(NULL, size - 1 - t, t, size, m_dev, a_dev, b_dev);

        // Launch Fan2
        cuda_fan2_launcher(NULL, size - 1 - t, size - t, t, size, m_dev, a_dev, b_dev);

        // Fan3 logic is embedded in Fan2 in the OpenCL version (when globalIdy == 0)
        // The original code had GenOnI(Fan3...), but the OpenCL Fan2 covers the b_dev update.
        // If strict separation is needed, we could add a Fan3 kernel, but Fan2 already does:
        // if(globalIdy == 0){ b_dev[globalIdx+1+t] -= ... }
        // So Fan3 is redundant if Fan2 runs with y-dimension >= 1.
    }
}

int main() {
    InitializeUs();
    MakeSharedVariables;  

    InitProblemOnce();
    InitPerRun();

    // Allocate CUDA memory
    float *a_dev, *b_dev, *m_dev;
    size_t a_size = Size * Size * sizeof(float);
    size_t b_size = Size * sizeof(float);
    size_t m_size = Size * Size * sizeof(float);

    cudaError_t err;
    err = cudaMalloc(&a_dev, a_size);
    if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc a failed\n"); exit(1); }
    err = cudaMalloc(&b_dev, b_size);
    if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc b failed\n"); exit(1); }
    err = cudaMalloc(&m_dev, m_size);
    if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc m failed\n"); exit(1); }

    // Copy initial data to device
    // Flatten a and m for CUDA
    float *a_flat = (float*)malloc(a_size);
    float *m_flat = (float*)malloc(m_size);

    for(int i=0; i<Size; i++) {
        for(int j=0; j<Size; j++) {
            a_flat[i*Size+j] = a[i][j];
            m_flat[i*Size+j] = m[i][j];
        }
    }

    cudaMemcpy(a_dev, a_flat, a_size, cudaMemcpyHostToDevice);
    cudaMemcpy(b_dev, b, b_size, cudaMemcpyHostToDevice);
    cudaMemcpy(m_dev, m_flat, m_size, cudaMemcpyHostToDevice);

    // Run CUDA version
    ForwardSub_CUDA(m_dev, a_dev, b_dev, Size);

    // Copy back
    cudaMemcpy(m_flat, m_dev, m_size, cudaMemcpyDeviceToHost);
    cudaMemcpy(a_flat, a_dev, a_size, cudaMemcpyDeviceToHost);
    cudaMemcpy(b, b_dev, b_size, cudaMemcpyDeviceToHost);

    // Update host structures
    for(int i=0; i<Size; i++) {
        for(int j=0; j<Size; j++) {
            m[i][j] = m_flat[i*Size+j];
            a[i][j] = a_flat[i*Size+j];
        }
    }

    printf("The result of matrix m is: \n");
    PrintMat(m, Size, Size);
    printf("The result of matrix a is: \n");
    PrintMat(a, Size, Size);
    printf("The result of array b is: \n");
    PrintAry(b, Size);

    // Cleanup
    cudaFree(a_dev);
    cudaFree(b_dev);
    cudaFree(m_dev);
    free(a_flat);
    free(m_flat);

    return 0;
}

